if (! function_exists('network_port_scanner')) {
    function network_port_scanner($host, $ports = null, $timeout = null, $max_ports = null)
    {
            $host = $host ?? '';
            $ports = $ports ?? 'common';
            $timeout = $timeout ?? 3;
            $max_ports = $max_ports ?? 100;

            $timeout = max(1, min(10, (int)$timeout));
            $max_ports = max(1, min(65535, (int)$max_ports));

            if (empty($host)) {
                return ['success' => false, 'error' => 'Host is required.'];
            }

            // Strip protocol
            $host = preg_replace('#^https?://#', '', $host);
            $host = preg_replace('#/.*$#', '', $host);

            // Resolve hostname to IP first
            $ip = @gethostbyname($host);
            $resolution = ($ip !== $host) ? $ip : null;

            // Parse port specification
            $port_list = [];

            // Named presets
            $presets = [
                'common' => [22, 25, 53, 80, 110, 143, 443, 465, 587, 993, 995, 3306, 3389, 5432, 6379, 8080, 8443, 27017],
                'web' => [80, 443, 8080, 8443, 3000, 5000, 8000, 8888, 9090],
