                'database' => [1433, 1521, 3306, 5432, 6379, 9042, 27017, 28015],
                'all' => range(1, 1024),
            ];

            $port_str = strtolower(trim($ports));

            if (isset($presets[$port_str])) {
                $port_list = $presets[$port_str];
            } elseif (preg_match('/^(\d+)-(\d+)$/', $port_str, $m)) {
                $start = (int)$m[1];
                $end = (int)$m[2];
                if ($start < 1) $start = 1;
                if ($end > 65535) $end = 65535;
