            }

            // Apply max_ports limit
            if (count($port_list) > $max_ports) {
                $port_list = array_slice($port_list, 0, $max_ports);
            }

            // Common port name mapping
            $port_names = [
                7 => 'echo', 9 => 'discard', 13 => 'daytime', 19 => 'chargen',
                21 => 'FTP', 22 => 'SSH', 23 => 'Telnet', 25 => 'SMTP',
