                8443 => 'HTTPS-Alt', 8444 => 'Bitcoin', 8500 => 'Consul',
                8888 => 'HTTP-Alt2', 9000 => 'Sonarr', 9001 => 'Tor',
                9042 => 'Cassandra', 9090 => 'Prometheus', 9092 => 'Kafka',
                9100 => 'Node-Exporter', 9200 => 'Elasticsearch', 9300 => 'Elasticsearch-Cluster',
                9418 => 'Git', 9999 => 'HTTP-Alt3', 10000 => 'Webmin',
                11211 => 'Memcached', 15672 => 'RabbitMQ',
                25565 => 'Minecraft', 27017 => 'MongoDB', 28017 => 'MongoDB-Status',
                32400 => 'Plex',
            ];

            // Helper: sanitize for JSON-safe UTF-8
            $sanitize = function($s) {
                return mb_convert_encoding($s, 'UTF-8', 'UTF-8');
            };

            // Scan ports
            $results = [];
            $open_count = 0;
            $closed_count = 0;
            $total_start = microtime(true);

            foreach ($port_list as $port) {
                $start = microtime(true);
                $errno = 0;
                $errstr = '';
